THE RISK:
{
 "id": "distributor-line-review-lockout",
 "title": "Annual line reviews and exclusivity terms lock the distribution channel for the launch year",
 "narrative": "The distributor cell (13%) and much of the mid/enterprise cell (25%) are reached through master distributors and reseller networks — the MaxPower model, where the distributor sells to resellers, not end customers. Those distributors run annual line reviews: category slots are allocated once a year, often with exclusivity or MDF commitments to the incumbent PDU line, and intelligent-PDU buyer guides note distributors already carry OEM/private-label options that fill the 'value' slot. A pre-launch entrant arrives mid-cycle into a category that is already filled twice over. The result is not a lower win rate — it is that the indirect channel produces zero Year-1 revenue while the model quietly assumes it contributes at the same 3% pace as everything else.",
 "category": "execution",
 "targetNodes": [
  "cust.distributor",
  "obtainableFactor"
 ],
 "mechanism": [
  {
   "step": "trigger",
   "text": "CE power-infrastructure distribution operates on the master-distributor model with annual line reviews; category slots for rack power are held by incumbent lines and supplemented by private-label ODM options the distributor already controls",
   "refs": [
    "digest:cust-mix#c8",
    "digest:cust-mix#c13",
    "ledger:cust.distributor"
   ]
  },
  {
   "step": "propagation",
   "text": "An entrant launching mid-cycle cannot obtain a line-card slot until the next review, and no corpus source quantifies indirect share or documents off-cycle onboarding — the mid/enterprise cell that buys through these resellers is similarly delayed, pushing all distribution-routed deals beyond the 12-month window",
   "refs": [
    "profile:Stage",
    "digest:cust-mix#c4",
    "ledger:cust.operator-mid"
   ]
  },
  {
   "step": "model-impact",
   "text": "cust.distributor (0.13) is unavailable for Year 1 and the blended Year-1 pace across remaining cells falls below the 3% mid-band, because the funnel applies one obtainableFactor uniformly across channels with radically different onboarding clocks",
   "refs": [
    "ledger:cust.distributor",
    "ledger:obtainableFactor"
   ]
  }
 ],
 "whyMissable": "Distribution looks like the easy channel — low share (0.13), low stakes, 'we'll sign a distributor when ready.' The kill detail is timing, not access: the ledger has no time dimension on buyer cells, so a channel that is open in month 14 and one that is open in month 1 look identical in the funnel.",
 "expectedObviousness": "medium",
 "falsifier": "A named CE power/IT-infrastructure distributor signs the venture's line off-cycle within 6 months of launch without exclusivity conflict — or documented evidence that CE distributors onboard new PDU vendors on rolling rather than annual review calendars.",
 "likelihood": {
  "value": 0.3,
  "rationale": "Annual line reviews with category exclusivity are standard practice in electrical/IT distribution (base rate of the channel model), but some challenger distributors deliberately onboard new lines off-cycle to differentiate [evidence revision: The trigger (master-distributor model, filled category slots, private-label value option) is confirmed, but the falsifier is partially met: multiple named IT/power-infrastructure distributors publicly onboarded new PDU/power vendors as standalone agreements across 2025-2026, and line-review governance sources note rolling calendars rather than strict single annual windows. This weakens the strong 'zero Year-1 indirect revenue' claim, lowering likelihood from 0.4 toward 0.3. It is not fully refuted because the evidence does not directly document off-cycle onboarding in the specific CE market with no exclusivity conflict, nor that these deals closed within 6 months of a vendor's launch.]",
  "basis": "evidence",
  "revisedFrom": 0.4
 },
 "perturbation": [
  {
   "nodeId": "cust.distributor",
   "op": "exclude",
   "note": "Distributor cell closed until next line-review cycle — outside the Year-1 window"
  },
  {
   "nodeId": "obtainableFactor",
   "op": "scale",
   "value": 0.7,
   "note": "Distribution-routed mid-market deals slip beyond Year 1, dragging the blended ramp below the 3% mid-band"
  }
 ],
 "indicators": [
  {
   "signal": "Rack-power category composition on published line cards of the top-5 CE power/IT-infrastructure distributors",
   "where": "Distributor line cards and published price lists (vendor pages of major CE electrical and IT distribution groups)",
   "threshold": "Category shows incumbent line + a private-label option in ≥4 of 5 line cards — both slots filled",
   "updates": "increases"
  },
  {
   "signal": "Response pattern to the venture's distribution inquiries",
   "where": "Venture's own channel-recruitment log across first 2 quarters",
   "threshold": "≥3 distributors respond 'category filled, revisit at next annual review'",
   "updates": "increases"
  }
 ],
 "mitigations": [
  {
   "action": "Map the line-review calendars, exclusivity terms and private-label arrangements of the top-5 CE distributors before committing the channel plan",
   "type": "information",
   "voiNodeId": "cust.distributor",
   "note": "Replaces an unevidenced 0.13 cell with a dated channel-opening schedule"
  },
  {
   "action": "Bridge Year 1 with a direct/rep-model sales motion and e-commerce for the mid-market, deferring distribution to the first open review cycle",
   "type": "operational",
   "voiNodeId": null,
   "note": null
  },
  {
   "action": "Offer a non-exclusive, high-margin category slot to a challenger distributor seeking differentiation from the incumbent-locked majors",
   "type": "contractual",
   "voiNodeId": null,
   "note": "Margin, not volume, is the currency that opens a mid-cycle slot"
  }
 ],
 "evidenceStatus": "contested",
 "evidence": [
  {
   "title": "Mayflex signs distribution agreement with Schleifenbauer",
   "sourceType": "industry-report",
   "publisher": "Data Centre & Network News",
   "date": "2025-07-31",
   "excerpt": "Mayflex... has announced a new distribution agreement with Schleifenbauer, adding the Netherlands-based manufacturer’s power distribution units (PDUs) and energy management tools to the Elevate brand’s data centre infrastructure portfolio.",
   "url": "https://dcnnmagazine.com/infrastructure/power-cooling/mayflex-signs-distribution-agreement-with-schleifenbauer/",
   "attached": true
  },
  {
   "title": "The Ultimate Guide to a Product Line Review (PLR)",
   "sourceType": "industry-report",
   "publisher": "Porchlight",
   "date": "2025-07-10",
   "excerpt": "PLRs typically occur on a rolling calendar by category. Some happen annually, while others may occur every two to three years. In lieu of a full PLR, retailers often conduct Business Reviews.",
   "url": "https://www.porchlightatl.com/product-line-review-plr-guide/",
   "attached": true
  },
  {
   "title": "MaxPower Corporation - Line Card",
   "sourceType": "industry-report",
